# Banned tokens (em dash and "not X but Y" formulations are partially guarded by author care; we'll sanitize em-dash)
def sanitize(text):
    # remove em-dash variants
    text = text.replace("—", "،")
    text = text.replace("–", "،")
    return text

def build_row_content(sign, house):
    intro = SIGN_INTRO[sign]
    block = HOUSE_BLOCK[house]
    flavor = SIGN_FLAVOR[sign]

    # traditional: combine sign intro + house traditional + flavor tone
    trad = f"{intro} {flavor['tone']}. {block['trad']}"

    # evolutionary: house evol + sign-evol extra
    evol = f"{block['evol']} {flavor['evol_extra']}"

    # developmental task: emphasize الخطر الوهمي (heavy), then matrix
    task = f"{block['task']} {flavor['task_extra']}"

    # References: choose 2-3
    refs_primary = HOUSE_REF_PRIMARY[house]
    add = SIGN_REF_ADD[sign]
    refs = list(refs_primary)
    if add not in refs:
        refs.append(add)
    # keep max 3
    refs = refs[:3]
    refs_str = "; ".join(refs)

    return sanitize(trad), sanitize(evol), sanitize(task), refs_str

def main():
    rows = []
    with open(SRC, encoding="utf-8", newline="") as f:
        reader = csv.reader(f)
        header = next(reader)
        rows.append(header)
        for r in reader:
            sign = r[4]
            house = r[5]
            trad, evol, task, refs = build_row_content(sign, house)
            r[8] = trad
            r[9] = evol
            r[10] = task
            r[11] = refs
            r[12] = "filled"
            rows.append(r)

    os.makedirs(os.path.dirname(DST), exist_ok=True)
    with open(DST, "w", encoding="utf-8", newline="") as f:
        writer = csv.writer(f)
        for r in rows:
            writer.writerow(r)

    # Verify
    with open(DST, encoding="utf-8", newline="") as f:
        reader = csv.reader(f)
        all_rows = list(reader)

    data_rows = all_rows[1:]
    print(f"Header columns: {len(all_rows[0])}")
    print(f"Data rows: {len(data_rows)}")

    # Word counts per row
    bad = []
    for r in data_rows:
        wc = len(r[8].split()) + len(r[9].split()) + len(r[10].split())
        if wc < 200 or wc > 350:
            bad.append((r[6], wc))
        # check em-dash
        if any("—" in r[i] or "–" in r[i] for i in (8, 9, 10)):
            bad.append((r[6], "em-dash"))
    if bad:
        print("WARN issues:", bad[:10], "...total", len(bad))
    else:
        print("All rows in 200-350 word range; no em-dashes.")

    print(f"Written: {DST}")

if __name__ == "__main__":
    main()
